<?php
require __DIR__ . '/bootstrap.php';
$rows=[];if(defined('HS_INSTALLED')&&HS_INSTALLED){$r=mysqli_query(hs_db(),"SELECT title,slug,excerpt,image_main,created_at FROM hs_posts WHERE status='published' AND type='gallery' ORDER BY created_at DESC LIMIT 24");if($r)$rows=mysqli_fetch_all($r,MYSQLI_ASSOC);}?>
<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Photo Gallery</title><link rel='stylesheet' href='<?= hs_base_url('assets/css/style.css') ?>'></head><body><main class='page-bg'><div class='container'><div class='section-head'><h1>Photo Gallery</h1></div><div class='card-grid card-grid-3'><?php foreach($rows as $p):?><article class='news-card news-card-compact'><?php if(!empty($p['image_main'])):?><img src='<?= hs_base_url($p['image_main']) ?>' alt='<?= htmlspecialchars($p['title']) ?>'><?php endif;?><h3><a href='<?= hs_base_url('post.php?slug='.urlencode($p['slug'])) ?>'><?= htmlspecialchars($p['title']) ?></a></h3></article><?php endforeach; if(empty($rows)):?><div class='panel'>No galleries published yet.</div><?php endif;?></div></div></main></body></html>
